import sqlite3
import hashlib
import os
from contextlib import contextmanager

# Database configuration
DB_PATH = "legacy_users.db"


@contextmanager
def get_db_connection():
    """Context manager for database connections - ensures proper cleanup."""
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    try:
        yield conn
    finally:
        conn.close()


def init_database():
    """Initialize the users table if it doesn't exist (legacy schema compatible)."""
    with get_db_connection() as conn:
        cursor = conn.cursor()
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                username VARCHAR(255) NOT NULL UNIQUE,
                password_hash VARCHAR(255) NOT NULL,
                salt VARCHAR(255) NOT NULL,
                is_active INTEGER DEFAULT 1,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                last_login TIMESTAMP
            )
        """)
        conn.commit()


def _hash_password(password: str, salt: str) -> str:
    """Hash a password with the given salt using SHA-256 (legacy compatible)."""
    salted = salt + password
    return hashlib.sha256(salted.encode("utf-8")).hexdigest()


def create_user(username: str, password: str) -> bool:
    """Register a new user with a hashed password."""
    salt = os.urandom(32).hex()
    password_hash = _hash_password(password, salt)

    try:
        with get_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(
                "INSERT INTO users (username, password_hash, salt) VALUES (?, ?, ?)",
                (username, password_hash, salt),
            )
            conn.commit()
            print(f"User '{username}' created successfully.")
            return True
    except sqlite3.IntegrityError:
        print(f"Error: Username '{username}' already exists.")
        return False


def login(username: str, password: str) -> dict | None:
    """
    Authenticate a user by checking username and password against the users table.

    Args:
        username: The username to authenticate.
        password: The plaintext password to verify.

    Returns:
        A dict with user info if authentication succeeds, None otherwise.
    """
    if not username or not password:
        print("Error: Username and password are required.")
        return None

    with get_db_connection() as conn:
        cursor = conn.cursor()

        # Fetch user record from legacy users table
        cursor.execute(
            "SELECT id, username, password_hash, salt, is_active FROM users WHERE username = ?",
            (username,),
        )
        user = cursor.fetchone()

        if user is None:
            print("Login failed: Invalid username or password.")
            return None

        # Check if account is active (legacy systems may have deactivated accounts)
        if not user["is_active"]:
            print("Login failed: Account is deactivated.")
            return None

        # Verify password against stored hash
        computed_hash = _hash_password(password, user["salt"])

        if computed_hash != user["password_hash"]:
            print("Login failed: Invalid username or password.")
            return None

        # Update last login timestamp
        cursor.execute(
            "UPDATE users SET last_login = CURRENT_TIMESTAMP WHERE id = ?",
            (user["id"],),
        )
        conn.commit()

        print(f"Login successful. Welcome, {user['username']}!")
        return {
            "id": user["id"],
            "username": user["username"],
            "is_active": bool(user["is_active"]),
        }


def list_users():
    """List all users (admin utility)."""
    with get_db_connection() as conn:
        cursor = conn.cursor()
        cursor.execute("SELECT id, username, is_active, created_at, last_login FROM users")
        users = cursor.fetchall()
        print("\n--- Registered Users ---")
        for u in users:
            status = "active" if u["is_active"] else "inactive"
            print(f"  ID: {u['id']}, Username: {u['username']}, Status: {status}, "
                  f"Created: {u['created_at']}, Last Login: {u['last_login']}")
        print(f"Total: {len(users)} user(s)\n")


